# einmalig ausführen um Matrix zu speichern
using DelimitedFiles
using LinearAlgebra
using Printf
# Matrix aus dem funktionierenden Code laden
include("moduleTSeeqstQutrit.jl")
using .TSeeqstQutrit
using Random


Random.seed!(42)
N = 3

RhoTrue = GenerateRandomDensityMatrixQutrits(N)

# ── Verifikation ───────────────────────────────────────────────
println("── Verifikation ──")
println(@sprintf("  Spur:          %.6f", real(tr(RhoTrue))))
println(@sprintf("  Hermitisch:    %s",   RhoTrue ≈ RhoTrue'))
println(@sprintf("  Min Eigenwert: %.6f", minimum(real(eigvals(RhoTrue)))))
println(@sprintf("  Dim:           %s",   string(size(RhoTrue))))
println()

diag_vals   = real.(diag(RhoTrue))
n_zero_diag = count(x -> abs(x) < 1e-6, diag_vals)
println(@sprintf("  Diag=0: %d / %d", n_zero_diag, 3^N))
println()

# ── Speichern ──────────────────────────────────────────────────
writedlm("RhoTrue_real.csv", real(RhoTrue), ',')
writedlm("RhoTrue_imag.csv", imag(RhoTrue), ',')
println("✓ Matrix gespeichert")
println(RhoTrue)

